import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Electronics', path: '/electronics' },
    { name: 'Electrical', path: '/electrical' },
    { name: 'Chemical', path: '/chemical' },
    { name: 'Industries', path: '/industries' },
    { name: 'About', path: '/about' },
  ];

  return (
    <nav className={`fixed w-full z-[100] transition-all duration-700 px-6 md:px-12 ${scrolled ? 'top-4' : 'top-0'}`}>
      <div className={`mx-auto transition-all duration-700 overflow-hidden ${
        scrolled 
          ? 'max-w-5xl bg-white/70 backdrop-blur-2xl rounded-full border border-white/20 shadow-[0_20px_50px_rgba(0,0,0,0.1)] px-8 py-3' 
          : 'max-w-full bg-transparent py-8 border-b border-gray-100/10'
      }`}>
        <div className="flex justify-between items-center">

          {/* 1. BRAND LOGO */}
          <Link to="/" className="relative group overflow-hidden">
            <div className="flex flex-col">
              <span className={`text-2xl font-black tracking-tighter transition-colors duration-500 ${scrolled ? 'text-gray-900' : 'text-gray-900'}`}>
                HUDSON<span className="text-orange-600">.</span>
              </span>
              <span className={`text-[8px] font-bold tracking-[0.4em] uppercase transition-all duration-500 ${scrolled ? 'opacity-0 -translate-y-2' : 'opacity-100'}`}>
                Consultancy
              </span>
            </div>
          </Link>

          {/* 2. CENTER NAVIGATION (Desktop) */}
          <div className="hidden lg:flex items-center gap-1">
            {navLinks.map((link) => {
              const isActive = location.pathname === link.path;
              return (
                <Link
                  key={link.name}
                  to={link.path}
                  className={`px-4 py-2 text-[13px] font-bold uppercase tracking-widest transition-all duration-300 rounded-full relative group ${
                    isActive ? 'text-orange-600' : 'text-gray-500 hover:text-gray-900'
                  }`}
                >
                  {link.name}
                  {/* Underline Animation */}
                  <span className={`absolute bottom-0 left-1/2 -translate-x-1/2 h-1 w-1 bg-orange-600 rounded-full transition-all duration-300 ${isActive ? 'opacity-100 scale-100' : 'opacity-0 scale-0 group-hover:opacity-100 group-hover:scale-100'}`}></span>
                </Link>
              );
            })}
          </div>

          {/* 3. RIGHT CTA SECTION */}
          <div className="flex items-center gap-6">
            <Link to="/careers" className="hidden sm:block text-[11px] font-black uppercase tracking-widest text-gray-400 hover:text-orange-600 transition-colors">
              Join Team
            </Link>

            <button className={`px-6 py-2.5 rounded-full font-bold text-xs uppercase tracking-widest transition-all duration-500 ${
              scrolled 
                ? 'bg-orange-600 text-white hover:bg-gray-900 shadow-lg shadow-orange-200' 
                : 'bg-gray-950 text-white hover:bg-orange-600 shadow-xl'
            }`}>
              Let's Talk
            </button>

            {/* Mobile Toggle Button */}
            <button 
              onClick={() => setIsOpen(!isOpen)}
              className="lg:hidden flex flex-col gap-1 w-6 group"
            >
              <span className={`h-0.5 bg-gray-900 rounded-full transition-all duration-300 ${isOpen ? 'rotate-45 translate-y-1.5 w-6' : 'w-6'}`}></span>
              <span className={`h-0.5 bg-gray-900 rounded-full transition-all duration-300 ${isOpen ? 'opacity-0' : 'w-4 group-hover:w-6'}`}></span>
              <span className={`h-0.5 bg-gray-900 rounded-full transition-all duration-300 ${isOpen ? '-rotate-45 -translate-y-1.5 w-6' : 'w-6'}`}></span>
            </button>
          </div>
        </div>
      </div>

      {/* 4. MODERN DRAWER MENU (Mobile) */}
      <div className={`fixed inset-0 bg-white/95 backdrop-blur-xl z-[-1] transition-all duration-700 lg:hidden ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex flex-col justify-center items-center h-full space-y-8">
           {navLinks.map((link, i) => (
             <Link
              key={i}
              to={link.path}
              onClick={() => setIsOpen(false)}
              className="text-5xl font-black text-gray-900 hover:text-orange-600 transition-all tracking-tighter"
             >
               {link.name}
             </Link>
           ))}
           <div className="pt-12 text-center">
              <p className="text-gray-400 text-xs tracking-widest mb-4">SOCIALS</p>
              <div className="flex gap-6 text-sm font-bold">
                <span>LN</span><span>TW</span><span>FB</span>
              </div>
           </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
